def gen(rng, size):
    n = max(6, min(400, size))
    s = ''.join(rng.choice('ab') for _ in range(n))
    def rand_piece():
        if rng.random() < 0.3:
            return ''
        start = rng.randint(0, n - 1)
        end = rng.randint(start, min(n, start + 5))
        return s[start:end]
    p = rand_piece() + '*' + rand_piece() + '*' + rand_piece()
    return [s, p]

