class Solution:
    def shortestMatchingSubstring(self, s, p):
        star1 = p.index('*')
        star2 = p.index('*', star1 + 1)
        p1, p2, p3 = p[:star1], p[star1 + 1:star2], p[star2 + 1:]
        n = len(s)
        best = -1
        for i in range(n + 1):
            for j in range(i, n + 1):
                t = s[i:j]
                if len(t) < len(p1) + len(p3):
                    continue
                if not t.startswith(p1):
                    continue
                if not t.endswith(p3):
                    continue
                region = t[len(p1):len(t) - len(p3)]
                if p2 in region:
                    if best == -1 or (j - i) < best:
                        best = j - i
        return best

