var shortestMatchingSubstring = function(s, p) {
    const star1 = p.indexOf('*');
    const star2 = p.indexOf('*', star1 + 1);
    const p1 = p.slice(0, star1), p2 = p.slice(star1 + 1, star2), p3 = p.slice(star2 + 1);

    function findAll(text, pat) {
        if (pat === '') {
            const res = [];
            for (let i = 0; i <= text.length; i++) res.push(i);
            return res;
        }
        const res = [];
        let start = 0;
        while (true) {
            const idx = text.indexOf(pat, start);
            if (idx === -1) break;
            res.push(idx);
            start = idx + 1;
        }
        return res;
    }

    function lowerBound(arr, target) {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }

    const pos1 = findAll(s, p1);
    const pos2 = findAll(s, p2);
    const pos3 = findAll(s, p3);

    let best = -1;
    for (const i1 of pos1) {
        const j = i1 + p1.length;
        const k = lowerBound(pos2, j);
        if (k === pos2.length) continue;
        const i2 = pos2[k];
        const j2 = i2 + p2.length;
        const m = lowerBound(pos3, j2);
        if (m === pos3.length) continue;
        const i3 = pos3[m];
        const length = i3 + p3.length - i1;
        if (best === -1 || length < best) best = length;
    }
    return best;
};
